require_once __DIR__.'/functions.php';require_once __DIR__.'/mail.php';require_login();$staff=current_staff_profile();if(!$staff){http_response_code(400);exit('Tu acceso proviene de .env. Crea una cuenta administrativa MySQL para usar un perfil social.');}
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();try{$name=trim((string)($_POST['display_name']??''));$email=strtolower(trim((string)($_POST['email']??'')));$bio=trim((string)($_POST['bio']??''));$public=isset($_POST['profile_public'])?1:0;if(mb_strlen($name)<2||mb_strlen($name)>100||mb_strlen($bio)>500||!filter_var($email,FILTER_VALIDATE_EMAIL))throw new RuntimeException('Revisa el nombre, correo y biografía.');$emailChanged=!hash_equals(strtolower((string)($staff['email']??'')),$email);$profileSlug=unique_staff_slug($name,(int)$staff['id']);$avatar=upload_avatar($_FILES['avatar']??[]);$pdo=db();$pdo->beginTransaction();$sql='UPDATE users SET display_name=?,email=?,bio=?,profile_public=?,profile_slug=?'.($emailChanged?',email_verified_at=NULL':'').($avatar?',avatar=?':'').' WHERE id=?';$args=[$name,$email,$bio,$public,$profileSlug];if($avatar)$args[]=$avatar;$args[]=$staff['id'];$pdo->prepare($sql)->execute($args);$pdo->prepare('UPDATE posts SET author_name=? WHERE author_id=?')->execute([$name,$staff['id']]);$pdo->prepare('UPDATE comments SET nombre=?,email=? WHERE staff_author_id=?')->execute([$name,$email,$staff['id']]);$pdo->commit();if($avatar)delete_image($staff['avatar']??null);$_SESSION['display_name']=$name;if($emailChanged){send_staff_verification_email(['id'=>$staff['id'],'email'=>$email]);flash('Perfil actualizado. Revisa el nuevo correo para verificarlo.');}else{flash('Perfil del autor actualizado.');}redirect('/staff-profile.php');}catch(Throwable $e){if(isset($pdo)&&$pdo->inTransaction())$pdo->rollBack();flash($e instanceof PDOException?'Ese correo ya está en uso.':$e->getMessage(),'error');}}
